// Shared, client-safe types for the Kanban board.

export type Column = "todo" | "doing" | "done";

export interface CardDTO {
  id: number;
  title: string;
  position: number;
}

export interface BoardDTO {
  todo: CardDTO[];
  doing: CardDTO[];
  done: CardDTO[];
}

export interface MoveRequest {
  cardId: number;
  toColumn: Column;
  toIndex: number;
}

// Pure, client-safe board logic. No server-only imports here so this module is
// safe to bundle into the client. Both the optimistic client update and the
// server persistence share this implementation to stay consistent.

import type { BoardDTO, CardDTO, Column, MoveRequest } from "../types";

export const COLUMNS: Column[] = ["todo", "doing", "done"];

export function isColumn(value: unknown): value is Column {
  return value === "todo" || value === "doing" || value === "done";
}

export function emptyBoard(): BoardDTO {
  return { todo: [], doing: [], done: [] };
}

/** The initial seed board (order top-to-bottom within each column). */
export function seedBoard(): BoardDTO {
  return {
    todo: [
      { id: 1, title: "Design landing page", position: 0 },
      { id: 2, title: "Write unit tests", position: 1 },
      { id: 3, title: "Set up CI", position: 2 },
    ],
    doing: [
      { id: 4, title: "Implement auth", position: 0 },
      { id: 5, title: "Refactor store", position: 1 },
    ],
    done: [{ id: 6, title: "Project scaffolding", position: 0 }],
  };
}

export class HttpError extends Error {
  status: number;
  constructor(status: number, message: string) {
    super(message);
    this.status = status;
  }
}

/**
 * Apply a move to a board, returning a NEW board with contiguous 0-based
 * positions in every affected column. Throws HttpError on invalid input.
 *
 * Semantics:
 *  - Remove the card from its source column.
 *  - Insert it into `toColumn` at `toIndex` (clamped: negative -> 0, greater
 *    than the target column's card count -> append at the end).
 *  - Re-number positions contiguously (0..n-1) in every column.
 */
export function applyMoveToBoard(
  board: BoardDTO,
  cardId: number,
  toColumn: Column,
  toIndex: number,
): BoardDTO {
  if (!isColumn(toColumn)) {
    throw new HttpError(400, `Invalid toColumn: ${String(toColumn)}`);
  }
  if (!Number.isInteger(cardId)) {
    throw new HttpError(400, "Invalid cardId");
  }

  // Locate the card being moved and its source column.
  let fromColumn: Column | null = null;
  let movedCard: CardDTO | null = null;
  for (const col of COLUMNS) {
    const found = board[col].find((c) => c.id === cardId);
    if (found) {
      fromColumn = col;
      movedCard = found;
      break;
    }
  }
  if (!movedCard || !fromColumn) {
    throw new HttpError(404, `Card ${cardId} not found`);
  }

  // Build ordered id lists per column.
  const lists: Record<Column, number[]> = {
    todo: board.todo.map((c) => c.id),
    doing: board.doing.map((c) => c.id),
    done: board.done.map((c) => c.id),
  };

  // Remove the card from its source column.
  lists[fromColumn] = lists[fromColumn].filter((id) => id !== cardId);

  // Clamp the target index against the target column's current length (which,
  // for a same-column move, already excludes the moved card).
  const targetList = lists[toColumn];
  let idx = toIndex;
  if (!Number.isFinite(idx)) {
    idx = targetList.length;
  }
  if (idx < 0) idx = 0;
  if (idx > targetList.length) idx = targetList.length;

  // Insert the card at the computed index.
  targetList.splice(idx, 0, cardId);

  // Build a lookup of card -> title from the original board.
  const titleById = new Map<number, string>();
  for (const col of COLUMNS) {
    for (const c of board[col]) titleById.set(c.id, c.title);
  }

  // Re-number positions contiguously and produce the new board.
  const next: BoardDTO = emptyBoard();
  for (const col of COLUMNS) {
    next[col] = lists[col].map((id, position) => ({
      id,
      title: titleById.get(id) ?? "",
      position,
    }));
  }
  return next;
}

/** Validate a parsed move request body. Throws HttpError(400) if invalid. */
export function validateMoveBody(body: unknown): MoveRequest {
  if (!body || typeof body !== "object") {
    throw new HttpError(400, "Invalid JSON body");
  }
  const b = body as Record<string, unknown>;
  const cardId = b.cardId;
  const toColumn = b.toColumn;
  const toIndex = b.toIndex;
  if (
    typeof cardId !== "number" ||
    !Number.isInteger(cardId) ||
    typeof toColumn !== "string" ||
    !isColumn(toColumn) ||
    typeof toIndex !== "number" ||
    !Number.isFinite(toIndex)
  ) {
    throw new HttpError(400, "Missing or invalid fields");
  }
  return { cardId, toColumn, toIndex };
}

// SERVER-ONLY module: all SQLite access lives here. This must never be imported
// from client code. It is only used inside `routeLoader$` and server endpoints,
// which Qwik strips out of the client bundle.

import { existsSync, mkdirSync } from "node:fs";
import { dirname, join } from "node:path";
import Database from "better-sqlite3";
import type { BoardDTO, CardDTO, Column } from "../types";
import { applyMoveToBoard, COLUMNS, HttpError, seedBoard } from "../lib/board";

export type { BoardDTO, CardDTO, Column };

const DB_PATH = join(process.cwd(), "data", "board.sqlite");

// Reuse a single connection across hot reloads in dev (Next-style global trick).
const globalForDb = globalThis as unknown as { __boardDb?: Database.Database };

function createDb(): Database.Database {
  const dir = dirname(DB_PATH);
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  const db = new Database(DB_PATH);
  db.pragma("journal_mode = WAL");
  db.exec(`
    CREATE TABLE IF NOT EXISTS cards (
      id       INTEGER PRIMARY KEY,
      title    TEXT NOT NULL,
      column   TEXT NOT NULL,
      position INTEGER NOT NULL
    );
  `);
  seedIfEmpty(db);
  return db;
}

export function getDb(): Database.Database {
  if (!globalForDb.__boardDb) {
    globalForDb.__boardDb = createDb();
  }
  return globalForDb.__boardDb;
}

interface CardRow {
  id: number;
  title: string;
  column: string;
  position: number;
}

function seedIfEmpty(db: Database.Database): void {
  const count = db
    .prepare("SELECT COUNT(*) AS n FROM cards")
    .get() as { n: number };
  if (count.n > 0) return;
  const seed = seedBoard();
  const insert = db.prepare(
    "INSERT INTO cards (id, title, column, position) VALUES (?, ?, ?, ?)",
  );
  const tx = db.transaction(() => {
    for (const col of COLUMNS) {
      for (const card of seed[col]) {
        insert.run(card.id, card.title, col, card.position);
      }
    }
  });
  tx();
}

/** Read the full board from the database, ordered by position within columns. */
export function getBoard(): BoardDTO {
  const db = getDb();
  const rows = db
    .prepare("SELECT id, title, column, position FROM cards ORDER BY column, position ASC")
    .all() as CardRow[];

  const board: BoardDTO = { todo: [], doing: [], done: [] };
  for (const row of rows) {
    if (row.column in board) {
      (board as unknown as Record<string, CardDTO[]>)[row.column].push({
        id: row.id,
        title: row.title,
        position: row.position,
      });
    }
  }
  return board;
}

/** Apply a move and persist it. Returns the updated board. */
export function moveCard(
  cardId: number,
  toColumn: Column,
  toIndex: number,
): BoardDTO {
  const current = getBoard();
  const next = applyMoveToBoard(current, cardId, toColumn, toIndex);

  const db = getDb();
  const update = db.prepare(
    "UPDATE cards SET column = ?, position = ? WHERE id = ?",
  );
  const tx = db.transaction(() => {
    for (const col of COLUMNS) {
      for (const card of next[col]) {
        update.run(col, card.position, card.id);
      }
    }
  });
  tx();
  return next;
}

/** Reset the database to the exact initial seed. Returns the seeded board. */
export function resetBoard(): BoardDTO {
  const db = getDb();
  const tx = db.transaction(() => {
    db.prepare("DELETE FROM cards").run();
    const seed = seedBoard();
    const insert = db.prepare(
      "INSERT INTO cards (id, title, column, position) VALUES (?, ?, ?, ?)",
    );
    for (const col of COLUMNS) {
      for (const card of seed[col]) {
        insert.run(card.id, card.title, col, card.position);
      }
    }
  });
  tx();
  return getBoard();
}

export { HttpError };

import type { RequestHandler } from "@builder.io/qwik-city";
import { getBoard } from "~/db/board";

export const onGet: RequestHandler = ({ json }) => {
  const board = getBoard();
  json(200, board);
};

import type { RequestHandler } from "@builder.io/qwik-city";
import { HttpError, moveCard, validateMoveBody } from "~/db/board";

export const onPost: RequestHandler = async ({ json, request }) => {
  let body: unknown;
  try {
    body = await request.json();
  } catch {
    json(400, { error: "Invalid JSON body" });
    return;
  }

  let cardId: number;
  let toColumn: "todo" | "doing" | "done";
  let toIndex: number;
  try {
    const parsed = validateMoveBody(body);
    cardId = parsed.cardId;
    toColumn = parsed.toColumn;
    toIndex = parsed.toIndex;
  } catch (err) {
    const status = err instanceof HttpError ? err.status : 400;
    json(status, { error: (err as Error).message });
    return;
  }

  try {
    const board = moveCard(cardId, toColumn, toIndex);
    json(200, board);
  } catch (err) {
    const status = err instanceof HttpError ? err.status : 400;
    json(status, { error: (err as Error).message });
  }
};

import type { RequestHandler } from "@builder.io/qwik-city";
import { resetBoard } from "~/db/board";

export const onPost: RequestHandler = ({ json }) => {
  const board = resetBoard();
  json(200, board);
};

